// formatComment applies safe basic formatting to comment text.
// It first escapes HTML, then applies simple markdown-like formatting.
// Supported: *bold*, _italic_, and auto-linking of URLs.
func formatComment(content string) template.HTML {
	// First, escape all HTML to prevent XSS
	escaped := template.HTMLEscapeString(content)

	// Apply bold: *text* (but not **)
	boldRe := regexp.MustCompile(`\*([^*]+)\*`)
	escaped = boldRe.ReplaceAllString(escaped, "<strong>$1</strong>")

	// Apply italic: _text_
	italicRe := regexp.MustCompile(`_([^_]+)_`)
	escaped = italicRe.ReplaceAllString(escaped, "<em>$1</em>")

	// Auto-link URLs (only http and https)
	urlRe := regexp.MustCompile(`(https?://[^\s<>"]+)`)
	escaped = urlRe.ReplaceAllStringFunc(escaped, func(url string) string {
		// Additional validation: ensure the URL doesn't contain javascript or data schemes after redirect
		safeURL := template.HTMLEscapeString(url)
		return `<a href="` + safeURL + `" rel="noopener noreferrer nofollow" target="_blank">` + safeURL + `</a>`
	})

	// Convert newlines to <br> tags
	escaped = strings.ReplaceAll(escaped, "\n", "<br>")

	return template.HTML(escaped)
}

